steps.tool_input:
{"path": "entrypoint.sh", "content": "#!/bin/sh
set -e

VARIANT=${1:-whole}
case "$VARIANT" in
  whole)
    exec /usr/local/bin/ljmd_whole "$2" "$3"
    ;;
  force)
    exec /usr/local/bin/ljmd_force "$2" "$3"
    ;;
  *)
    echo "Usage: $0 {whole|force} [args]" >&2
    exit 1
    ;;
esac
"}
